import api from "./api";
import { getAuthHeaders } from "./authService";

// Lấy danh sách sự kiện
export const getAllEvents = async (isAdmin = false, params = {}) => {
  const endpoint = isAdmin ? "/admin/events" : "/users/events";  // Đảm bảo API endpoint đúng
  try {
    const response = await api.get(endpoint, {
      params,
      headers: getAuthHeaders(),  // Đảm bảo token được gửi qua header
    });
    return response;
  } catch (error) {
    console.error("Lỗi khi lấy sự kiện:", error);
    throw new Error("Không thể lấy danh sách sự kiện");
  }
};

// Lấy chi tiết sự kiện theo ID
export const getEventById = async (id, isAdmin = false) => {
  const endpoint = isAdmin ? `/admin/events/${id}` : `/users/events/${id}`;
  try {
    const response = await api.get(endpoint, {
      headers: getAuthHeaders(),
    });
    return response;
  } catch (error) {
    console.error("Lỗi khi lấy chi tiết sự kiện:", error);
    throw new Error("Không thể lấy chi tiết sự kiện");
  }
};
